const raw = $input.first().json;
const body = raw.body ?? raw;
const rawUrls = body.urls ?? [];
const executionId = $execution?.id ?? Date.now().toString();

const clientId = String(body.client_id || body.clientId || '').trim();
const companyName = String(body.company_name || body.companyName || body.empresa || '').trim();

if (!clientId) throw new Error('client_id es obligatorio');
if (!companyName) throw new Error('company_name es obligatorio');

function normalizeInputUrl(value) {
  let input = String(value || '').trim();

  if (!input) return null;

  input = input
    .replace(/^["']+|["']+$/g, '')
    .replace(/\s+/g, '')
    .trim();

  // Quita protocolo si existe
  input = input.replace(/^https?:\/\//i, '');

  // Arregla casos como //aicor.com/ o /aicor.com/
  input = input.replace(/^\/+/, '');

  // Quita www solo para validar dominio, no para la URL final
  const firstSlashIndex = input.indexOf('/');
  const host = (firstSlashIndex === -1 ? input : input.slice(0, firstSlashIndex))
    .replace(/^www\./i, '')
    .toLowerCase();

  const path = firstSlashIndex === -1 ? '/' : input.slice(firstSlashIndex) || '/';

  if (!host || !/^[a-z0-9.-]+\.(com|es)$/.test(host)) {
    throw new Error('Solo se permiten dominios .com o .es: ' + host);
  }

  return {
    url: 'https://' + host + path,
    domain: host
  };
}

const inputUrls = Array.isArray(rawUrls) ? rawUrls : [rawUrls];
const normalized = [];

for (const inputUrl of inputUrls) {
  const result = normalizeInputUrl(inputUrl);
  if (!result) continue;

  if (!normalized.some((item) => item.url === result.url)) {
    normalized.push(result);
  }
}

if (normalized.length === 0) {
  throw new Error('Debes enviar al menos una URL');
}

if (normalized.length > 2) {
  throw new Error('Solo se permiten 2 URLs por cliente');
}

return normalized.map(({ url, domain }) => ({
  json: {
    url,
    rootUrl: url,
    rootDomain: domain,
    executionId,
    clientId,
    companyName
  }
}));

const parsed = $('0. Parsear URLs').item.json;
return [{
  json: {
    ...$json,
    url: parsed.url,
    rootUrl: parsed.rootUrl,
    rootDomain: parsed.rootDomain,
    executionId: parsed.executionId,
    clientId: parsed.clientId,
    companyName: parsed.companyName
  }
}];

const input = $json || {};
const html = String(input.body || input.data || input.html || '');

const links = [];
const anchorRegex = /<a\b[^>]*?href\s*=\s*(["'])(.*?)\1/gi;
let match;

while ((match = anchorRegex.exec(html)) !== null) {
  const href = String(match[2] || '').trim();
  if (href) links.push(href);
}

return [{
  json: {
    ...input,
    urls: links
  }
}];

const allUrls = Array.isArray($json.urls) ? $json.urls : [];
const rootUrl = String($json.rootUrl || $json.url || '').trim();
const rootDomain = String($json.rootDomain || '').toLowerCase().replace(/^www\./, '');
const executionId = $json.executionId || '';
const clientId = $json.clientId || $json.client_id || '';
const companyName = $json.companyName || $json.company_name || '';

function normalizeRootUrl(value) {
  let input = String(value || '').trim();
  input = input.replace(/^["']+|["']+$/g, '').replace(/\s+/g, '');
  input = input.replace(/^https?:\/\//i, '');
  input = input.replace(/^\/+/g, '');

  const slashIndex = input.indexOf('/');
  const host = (slashIndex === -1 ? input : input.slice(0, slashIndex))
    .replace(/^www\./i, '')
    .toLowerCase();
  let path = slashIndex === -1 ? '/' : input.slice(slashIndex);
  if (!path.startsWith('/')) path = '/' + path;

  return host ? 'https://' + host + path : '';
}

function normalizeHref(href) {
  let value = String(href || '').trim();

  if (!value) return null;
  value = value.replace(/^["']+|["']+$/g, '').replace(/\s+/g, '').trim();

  if (!value) return null;
  if (value.startsWith('#')) return null;
  if (/^(mailto|tel|javascript|data):/i.test(value)) return null;
  if (value.includes('@')) return null;

  value = value.split('#')[0];
  if (!value) return null;

  if (value.startsWith('//')) {
    value = value.replace(/^\/+/g, '');
  } else if (value.startsWith('/')) {
    value = rootDomain + value;
  } else {
    value = value.replace(/^https?:\/\//i, '');

    if (!/^[a-z0-9.-]+\.(com|es)(\/|$|\?)/i.test(value)) {
      value = value.replace(/^\.\//, '');
      value = rootDomain + '/' + value;
    }
  }

  value = value.replace(/^https?:\/\//i, '');
  value = value.replace(/^\/+/g, '');

  const slashIndex = value.indexOf('/');
  const queryIndex = value.indexOf('?');
  const firstSepCandidates = [slashIndex, queryIndex].filter((index) => index >= 0);
  const firstSep = firstSepCandidates.length ? Math.min(...firstSepCandidates) : -1;

  const host = (firstSep === -1 ? value : value.slice(0, firstSep))
    .replace(/^www\./i, '')
    .toLowerCase();

  let path = firstSep === -1 ? '/' : value.slice(firstSep);
  if (path.startsWith('?')) path = '/' + path;
  if (!path.startsWith('/')) path = '/' + path;

  if (!host || host !== rootDomain) return null;
  if (!/^[a-z0-9.-]+\.(com|es)$/.test(host)) return null;
  if (/\.(jpg|jpeg|png|gif|webp|svg|pdf|zip|rar|mp4|mp3|css|js|ico)(\?|$)/i.test(path)) return null;

  return 'https://' + host + path;
}

const cleanUrls = [];
const seen = new Set();
const rootNormalized = normalizeRootUrl(rootUrl);

if (rootNormalized) {
  seen.add(rootNormalized);
  cleanUrls.push(rootNormalized);
}

for (const href of allUrls) {
  const normalized = normalizeHref(href);
  if (!normalized) continue;

  if (!seen.has(normalized)) {
    seen.add(normalized);
    cleanUrls.push(normalized);
  }

  if (cleanUrls.length >= 25) break;
}

if (cleanUrls.length === 0) {
  return [{
    json: {
      url: rootUrl,
      rootUrl,
      rootDomain,
      executionId,
      clientId,
      companyName,
      warning: 'No se encontraron enlaces internos; se mantiene la URL raiz.'
    }
  }];
}

return cleanUrls.map((url) => ({
  json: {
    url,
    rootUrl,
    rootDomain,
    executionId,
    clientId,
    companyName
  }
}));

const input = $json || {};
const html = String(input.body || input.data || input.html || '');

function decodeEntities(text) {
  return String(text || '')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'");
}

let text = html
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
  .replace(/<[^>]+>/g, ' ');

text = decodeEntities(text).replace(/\s+/g, ' ').trim();

return [{
  json: {
    ...input,
    contenido: text ? [text.slice(0, 20000)] : [],
    extracted_chars: text.length
  }
}];

const source = $json || {};
const contenidoRaw = Array.isArray(source.contenido) ? source.contenido : [source.contenido || ''];
const contenidoLimpio = contenidoRaw
  .join(' ')
  .replace(/<[^>]*>?/gm, '')
  .replace(/\s+/g, ' ')
  .trim();

return {
  json: {
    url: source.url || '',
    rootUrl: source.rootUrl || '',
    rootDomain: source.rootDomain || '',
    executionId: source.executionId || '',
    client_id: source.clientId || source.client_id || '',
    company_name: source.companyName || source.company_name || '',
    contenido: contenidoLimpio,
    chars: contenidoLimpio.length
  }
};

const items = $input.all().map(item => item.json);
const results = items.map(item => ({
  url: item.url || '',
  status: item.chars > 0 ? 'done' : 'empty',
  chars: item.chars || (item.contenido || '').length,
  client_id: item.client_id || '',
  company_name: item.company_name || ''
}));

return [{
  json: {
    ok: true,
    client_id: results[0]?.client_id || '',
    company_name: results[0]?.company_name || '',
    total: results.length,
    results
  }
}];
